import React, { useEffect, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { createJobDescription, fetchAllEnableJobPositionData, fetchJobDescriptionById, fetchPositionById, updateJobDescription } from 'src/components/services/CareerApi';
import { CCol, CForm, CButton, CFormLabel } from '@coreui/react';
import FormInput from 'src/utils/FormInput';
import TextArea from 'src/utils/TextArea';
import Select from 'react-select';
import { v4 as uuidv4 } from 'uuid';
import authService from 'src/auth/auth.service';
import GoBackComponent from 'src/utils/GoBackComponent';

function JobDescriptionForm(props) {
  const location = useLocation();
  const redirectFromApplicant = location?.state?.redirectFromApplicant;
  const { type, id } = props;
  const [userData] = useState(authService.getUserDetailsFromLocalStorage());
  const [formData, setFormData] = useState({
    description: '',
    todoTitle: '',
    todoDescription: '',
    expectData: '',
    returnuTitle: '',
    returnuDescription: '',
    positionId: '',
    slug: "",
    jobType: "FULL_TIME",
    completed: false
  });
  const [todoList, setTodoList] = useState([{ title: '', description: '', _id: uuidv4() }]);
  const [returnu, setReturnU] = useState([{ title: '', description: '' }]);
  const [expect, setExpect] = useState([{ title: "", _id: uuidv4() }]);
  const [errors, setErrors] = useState({});
  const [errorMessage, setErrorMessage] = useState('');
  const [positionsOption, setPositionsOption] = useState([]);
  const [position, setPosition] = useState({});

  const navigate = useNavigate();

  useEffect(() => {
    if (type === 'EDIT') {
      fetchJobDescriptionDataById(id);
    }
    getAllPositions();
  }, []);

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.name === "slug" ? event.target.value.trimStart().replace(/ +/g, '').replace(/[!@^&\/\\#,+()$~%.'":*?<>{}]/g, '').toLowerCase() : event.target.value.trimStart().replace(/ +/g, ' ') });
  };

  const onChangeValue = (value) => {
    setFormData({ ...formData, jobType: value });
  }

  const fetchJobDescriptionDataById = async (id) => {
    let response = await fetchJobDescriptionById(id);
    if (response?.code === 200) {
      let data = {
        description: response?.results?.description,
        jobType: response?.results?.jobType,
        vacancy: response?.results?.vacancy,
        positionId: response?.results?.positionId?._id,
        departmentId: response?.results?.departmentId,
        slug: response?.results?.slug,
        completed: response?.results?.completed
      };
      setTodoList(response?.results?.todoData);
      setExpect(response?.results?.expectData && response?.results.expectData.map((item) => ({ "title": item, "_id": uuidv4() })));
      setReturnU(response?.results?.returnData);
      setPosition({ label: response?.results?.positionId?.title, value: response?.results?.positionId?._id, departmentId: response?.results?.departmentId });
      setFormData(data);
    }
  };

  const validateForm = (buttonType) => {
    let errors = {};
    let formIsValid = true;
    if (!position.value) {
      errors['position'] = 'Please select position';
      formIsValid = false;
    }
    if (buttonType !== "DRAFT") {
      if (!formData.description.trim()) {
        errors['description'] = 'Please select description';
        formIsValid = false;
      }
      if (!formData.slug) {
        errors['slug'] = 'Please enter slug';
        formIsValid = false;
      }
      todoList && todoList.forEach((data, index) => {
        const newArray = todoList;
        if (!data.title) {
          newArray[index].titleError = "Please enter title.";
          formIsValid = false;
        }
        if (!data.description) {
          newArray[index].descError = "Please enter description.";
          formIsValid = false;
        }
        setTodoList(newArray);
        setTimeout(() => {
          newArray[index].titleError = "";
          newArray[index].descError = "";
          setTodoList(newArray);
        }, 2000);
      });
      returnu && returnu.forEach((data, index) => {
        const newArray = returnu;
        if (!data.title) {
          newArray[index].titleError = "Please enter title.";
          formIsValid = false;
        }
        if (!data.description) {
          newArray[index].descError = "Please enter description.";
          formIsValid = false;
        }
        setReturnU(newArray);
        setTimeout(() => {
          newArray[index].titleError = "";
          newArray[index].descError = "";
          setReturnU(newArray);
        }, 2000);
      });
    }
    setErrorMessage(!formIsValid ? "One or more fields have an error. Please update them." : "");
    setErrors(errors);
    setTimeout(() => {
      setErrors({});
      setErrorMessage("");
    }, 2000);
    return formIsValid;
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm(event.target.name)) {
      let postData = {
        jobType: formData.jobType,
        description: formData.description,
        todoData: todoList && todoList.map((data) => ({ "title": data?.title, "description": data?.description })),
        expectData: expect && expect.map((data) => data?.title),
        returnData: returnu && returnu.map((data) => ({ "title": data?.title, "description": data?.description })),
        positionId: position.value,
        departmentId: position.departmentId,
        slug: formData?.slug,
        completed: event.target.name !== "DRAFT" ? true : false
      };
      let response = {};
      if (type === 'CREATE') {
        postData.createdBy = userData?.name;
        response = await createJobDescription(postData);
      } else {
        postData.id = id;
        response = await updateJobDescription(postData);
      }
      if (response?.code === 201 || response?.code === 202) {
        navigate('/career/job-description');
      }
      if (response?.code === 409) {
        setErrorMessage(response?.message);
      }
    }
    setTimeout(() => {
      setErrors({});
    }, 2000);
  };

  const handleAddTodo = () => {
    const newTodo = { title: '', description: '', _id: uuidv4() };
    setTodoList([...todoList, newTodo]);
  };

  const handleTodoChange = (event, id) => {
    const newState = todoList.map(obj => {
      if (obj._id === id) {
        return { ...obj, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') };
      }
      return obj;
    });
    setTodoList(newState);
  };

  const handleAddExpect = () => {
    const newExpect = { title: "", _id: uuidv4() };
    setExpect([...expect, newExpect]);
  };

  const handleExpectChange = (event, id) => {
    const newState = expect.map(obj => {
      if (obj._id === id) {
        return { ...obj, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') };
      }
      return obj;
    });
    setExpect(newState);
  };

  const handleAddReturnu = () => {
    const newState = { title: "", description: "", _id: uuidv4() };
    setReturnU([...returnu, newState]);
  };

  const handleReturnuChange = (event, id) => {
    const newState = returnu.map(obj => {
      if (obj._id === id) {
        return { ...obj, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') };
      }
      return obj;
    });
    setReturnU(newState);
  };

  const getAllPositions = async () => {
    let response = await fetchAllEnableJobPositionData();
    if (response?.code === 200) {
      let jobPosition = response.results && response.results.map((data) => { return { label: data.title, value: data._id, departmentId: data.departmentId } })
      setPositionsOption(jobPosition);
    }
  };

  const handleChangePosition = (position) => {
    setPosition(position);
  };

  const handleRemoveTodo = (id) => {
    let index = todoList.findIndex((data) => data._id === id);
    if (index > -1) {
      setTodoList([
        ...todoList.slice(0, index),
        ...todoList.slice(index + 1)
      ]);
    }
  };

  const handleRemoveReturn = (id) => {
    let index = returnu.findIndex((data) => data._id === id);
    if (index > -1) {
      setReturnU([
        ...returnu.slice(0, index),
        ...returnu.slice(index + 1)
      ]);
    }
  }

  const handleRemoveExpect = (id) => {
    let index = expect.findIndex((data) => data._id === id);
    if (index > -1) {
      setExpect([
        ...expect.slice(0, index),
        ...expect.slice(index + 1)
      ]);
    }
  }

  return (
    <>
      <GoBackComponent goBackData={"career/job-description"} />
      <div className='customContainer'>
        <CForm className='row g-3'>
          <CCol md={12}>
            <label>
              Position type
            </label>
            <div className="row">
              <CCol md={2}>
                <div class="custom-control custom-checkbox">
                  <label class="radio-container" onClick={(e) => onChangeValue("FULL_TIME")}>Full Time
                    <input type="radio" name="radio" className={formData?.jobType === "FULL_TIME" ? "checked" : ''} />
                    <span class="radio-checkmark"></span>
                  </label>
                </div>
              </CCol>
              <CCol md={3}>
                <div class="custom-control custom-checkbox">
                  <label class="radio-container" onClick={(e) => onChangeValue("INTERN")}>Intern
                    <input type="radio" name="radio" className={formData?.jobType === "INTERN" ? "checked" : ''} />
                    <span class="radio-checkmark"></span>
                  </label>
                </div>
              </CCol>
            </div>
          </CCol>
          <CCol md={6}>
            <div className='form-group'>
              <CFormLabel htmlFor='exampleFormControlTextarea1'>
                Select Position <span className='text-danger'>*</span>
              </CFormLabel>
              <Select
                placeholder={'Select type'}
                className='wnforSelect'
                name={'userFilterOption'}
                options={positionsOption}
                value={position}
                onChange={handleChangePosition}
                classNamePrefix="select"
                styles={{
                  option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                    const color = '#03a68059';
                    return {
                      ...styles,
                      backgroundColor: isDisabled
                        ? null
                        : isSelected
                          ? '#03a68059'
                          : isFocused
                            ? '#03a68059'
                            : null,
                      color: isDisabled
                        ? '#ccc'
                        : isSelected
                          ? color > 2
                            ? '#00374d'
                            : '#00374d'
                          : data.color,
                      cursor: isDisabled ? 'not-allowed' : 'default',

                      ':active': {
                        ...styles[':active'],
                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                      },
                    };
                  },
                }}
              />
              {errors['position'] && <div className='text-danger'>{errors['position']}</div>}
            </div>
          </CCol>
          <CCol md={8}>
            <FormInput
              value={formData.slug}
              label={'Slug'}
              name={`slug`}
              required
              onChange={handleChange}
              disabled={type !== "CREATE" && formData?.completed}
              error={errors['slug']}
            />
          </CCol>
          <CCol md={12}>
            <TextArea
              label={'Description'}
              name='description'
              required
              value={formData.description}
              onChange={handleChange}
              error={errors['description']}
            />
          </CCol>
          <CFormLabel> What are you going to do section <span className="text-danger">*</span></CFormLabel>
          {todoList && todoList.map((item, index) => (
            <React.Fragment key={item._id}>
              <CCol md={8}>
                <FormInput
                  value={item.title}
                  label={'Title'}
                  name={`title`}
                  required
                  onChange={(event) => handleTodoChange(event, item._id)}
                  error={item?.titleError}
                />
              </CCol>
              <CCol md={12}>
                <TextArea
                  label={'Description'}
                  name={`description`}
                  required
                  value={item.description}
                  onChange={(event) => handleTodoChange(event, item._id)}
                  error={item?.descError}
                />
              </CCol>
              {!redirectFromApplicant && index > 0 && (
                <CCol md={12}>
                  <CButton color="danger" onClick={() => handleRemoveTodo(item._id)} className="d-block">
                    Delete Section
                  </CButton>
                </CCol>
              )}
              <hr />
            </React.Fragment>
          ))}
          {!redirectFromApplicant && <CCol md={12}>
            <CButton color='primary' onClick={handleAddTodo} className='d-block'>
              Add Section
            </CButton>
          </CCol>}
          <CFormLabel> What do we expect section</CFormLabel>
          {expect && expect.map((item, index) => (
            <React.Fragment key={item._id}>
              <CCol md={12}>
                <FormInput
                  value={item.title}
                  label={'Title'}
                  name={`title`}
                  onChange={(event) => handleExpectChange(event, item._id)}
                />
              </CCol>
              {!redirectFromApplicant && index > 0 && (
                <CCol md={12}>
                  <CButton color="danger" onClick={() => handleRemoveExpect(item._id)} className="d-block">
                    Delete Section
                  </CButton>
                </CCol>
              )}
              <hr />
            </React.Fragment>
          ))}
          {!redirectFromApplicant && <CCol md={12}>
            <CButton color='primary' onClick={handleAddExpect} className='d-block'>
              Add Section
            </CButton>
          </CCol>}
          <CFormLabel> What you get in return section <span className="text-danger">*</span></CFormLabel>
          {returnu && returnu.map((item, index) => (
            <React.Fragment key={item._id}>
              <CCol md={8}>
                <FormInput
                  value={item.title}
                  label={'Title'}
                  name={`title`}
                  required
                  onChange={(event) => handleReturnuChange(event, item._id)}
                  error={item?.titleError}
                />
              </CCol>
              <CCol md={12}>
                <TextArea
                  label={'Description'}
                  name={`description`}
                  required
                  value={item.description}
                  onChange={(event) => handleReturnuChange(event, item._id)}
                  error={item?.descError}
                />
              </CCol>
              {!redirectFromApplicant && index > 0 && (
                <CCol md={12}>
                  <CButton color="danger" onClick={() => handleRemoveReturn(item._id)} className="d-block">
                    Delete Section
                  </CButton>
                </CCol>
              )}
              <hr />
            </React.Fragment>
          ))}
          {!redirectFromApplicant && 
            <CCol md={12}>
              <CButton color='primary' onClick={handleAddReturnu} className='d-block'>
                Add Section
              </CButton>
            </CCol>
          }
          {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
          {!redirectFromApplicant && 
            <CCol md={12} style={{ textAlign: "right" }}>
              {!formData?.completed && 
                <CButton color='primary' name={"DRAFT"} onClick={handleSubmit} style={{ marginRight: "10px" }}>
                  Save as Draft
                </CButton>
              }
            {authService.getPermission(props.type === 'CREATE' ? "JOB_DESCRIPTION_CREATE" : "JOB_DESCRIPTION_UPDATE") && 
                <CButton color='primary' name={"CREATE"} onClick={handleSubmit}>
                  {(props.type === 'CREATE' || !formData?.completed) ? 'Create' : 'Update'}
                </CButton>
              }
            </CCol>
          }
        </CForm>
      </div>
    </>
  );
}

export default JobDescriptionForm;
